const allTemplates: Template[] = [
  ...richTemplates,
  ...templateStubs.map(makeFullTemplate),
  ...remainingSlugs.map(makeStubTemplate),
]

export { allTemplates as templates }

export function getTemplateBySlug(slug: string): Template | undefined {
  return allTemplates.find(t => t.slug === slug)
}

export function getTemplatesByCategory(category: string): Template[] {
  return allTemplates.filter(t => t.category === category)
}

export function getPopularTemplates(limit = 12): Template[] {
  return allTemplates
    .sort((a, b) => b.downloadCount - a.downloadCount)
    .slice(0, limit)
}

export function getRelatedTemplates(slugs: string[]): Template[] {
  return slugs
    .map(s => allTemplates.find(t => t.slug === s))
    .filter((t): t is Template => t !== undefined)
    .slice(0, 6)
}
